:root {
  /* Color system */
  --color-primary-900: #07162C;  /* Header background from design */
  --color-primary-800: #111827;

  --color-secondary-50: #F5F7FB; /* Page background */
  --color-secondary-100: #E5E7EB; /* Card borders, dividers */

  --color-accent-500: #FF5A1F;   /* Links, highlights */

  --color-neutral-0: #FFFFFF;
  --color-neutral-200: #E5E7EB;
  --color-neutral-500: #6B7280;  /* Muted text */
  --color-neutral-800: #1F2933;  /* Primary text */

  --color-success: #16A34A;
  --color-error: #DC2626;
  --color-warning: #F59E0B;
  --color-info: #2563EB;

  /* Typography */
  --font-heading: "Space Grotesk", "Helvetica", sans-serif;
  --font-body: "Source Sans 3", "Arial", sans-serif;
  --font-code: "Source Code Pro", monospace;

  --font-size-h1: 32px;
  --font-size-h2: 22px;
  --font-size-h3: 18px;
  --font-size-body: 15px;
  --font-size-small: 13px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.25;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  /* Spacing scale (8px base) */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  /* Radii */
  --radius-xs: 3px;
  --radius-sm: 4px;
  --radius-md: 6px;  /* Search bar / cards */
  --radius-lg: 8px;

  /* Shadows */
  --shadow-card: 0 1px 2px rgba(15, 23, 42, 0.06);
  --shadow-subtle: 0 0 0 1px rgba(15, 23, 42, 0.04);

  /* Layout */
  --layout-max-width: 1040px;
}

/* Reset & base */
*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  font-size: 16px;
}

body {
  margin: 0;
  min-height: 100vh;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-relaxed);
  color: var(--color-neutral-800);
  background-color: var(--color-secondary-50);
}

a {
  color: var(--color-accent-500);
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: underline;
}

img {
  max-width: 100%;
  display: block;
}

.visually-hidden {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

h1,
h2,
h3,
h4,
h5,
h6 {
  margin: 0 0 var(--space-3);
  font-family: var(--font-heading);
  line-height: var(--line-height-tight);
  color: var(--color-primary-900);
}

h1 {
  font-size: var(--font-size-h1);
  font-weight: var(--font-weight-bold);
}

h2 {
  font-size: var(--font-size-h2);
  font-weight: var(--font-weight-semibold);
}

h3 {
  font-size: var(--font-size-h3);
  font-weight: var(--font-weight-semibold);
}

p {
  margin: 0 0 var(--space-3);
}

small {
  font-size: var(--font-size-small);
}

code,
pre {
  font-family: var(--font-code);
}

/* Layout wrappers */
.site-main {
  width: 100%;
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: var(--space-5) var(--space-3) var(--space-6);
}

@media (min-width: 768px) {
  .site-main {
    padding-top: var(--space-6);
  }
}

/* Header */
.site-header {
  background-color: var(--color-primary-900);
  color: var(--color-neutral-0);
  padding: var(--space-4) 0 var(--space-3);
}

@media (min-width: 768px) {
  .site-header {
    padding-bottom: var(--space-4);
  }
}

.header-inner {
  width: 100%;
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: 0 var(--space-3);
}

.header-brand-row {
  margin-bottom: var(--space-3);
}

.site-logo {
  font-family: var(--font-heading);
  font-size: 1.1rem;
  font-weight: var(--font-weight-bold);
  letter-spacing: 0.02em;
  color: var(--color-neutral-0);
}

.site-logo:hover,
.site-logo:focus {
  text-decoration: none;
}

/* Search bar reflecting design */
.header-search-row {
  margin-bottom: var(--space-3);
}

.site-search {
  margin: 0;
}

.site-search input[type="search"] {
  width: 100%;
  border-radius: var(--radius-md);
  border: 1px solid rgba(148, 163, 184, 0.6); /* mid grey border */
  background-color: rgba(148, 163, 184, 0.35); /* muted grey fill similar to screenshot */
  color: var(--color-neutral-0);
  padding: 12px 20px;
  font-size: 0.95rem;
  outline: none;
  transition: border-color 0.15s ease, background-color 0.15s ease, box-shadow 0.15s ease;
}

.site-search input[type="search"]::placeholder {
  color: rgba(229, 231, 235, 0.85);
}

.site-search input[type="search"]:focus {
  border-color: var(--color-accent-500);
  background-color: rgba(15, 23, 42, 0.6);
  box-shadow: 0 0 0 1px rgba(255, 90, 31, 0.6);
}

/* Primary navigation under search */
.primary-nav {
  border-top: 1px solid rgba(15, 23, 42, 0.4);
  padding-top: var(--space-2);
  margin-top: var(--space-1);
  overflow-x: auto;
}

.primary-nav-list {
  list-style: none;
  display: flex;
  flex-wrap: nowrap;
  gap: var(--space-3);
  margin: 0;
  padding: 0;
}

.primary-nav-item {
  flex: 0 0 auto;
}

.primary-nav-link {
  display: inline-flex;
  align-items: center;
  padding-bottom: 6px;
  font-size: 0.9rem;
  font-weight: var(--font-weight-medium);
  white-space: nowrap;
  color: rgba(249, 250, 251, 0.9);
  border-bottom: 2px solid transparent;
  transition: color 0.15s ease, border-color 0.15s ease;
}

.primary-nav-link:hover,
.primary-nav-link:focus {
  color: #ffffff;
  border-bottom-color: rgba(255, 255, 255, 0.4);
  text-decoration: none;
}

.primary-nav-link[aria-current="page"] {
  color: #ffffff;
  border-bottom-color: var(--color-accent-500);
}

/* Footer */
.site-footer {
  border-top: 1px solid var(--color-secondary-100);
  background-color: var(--color-neutral-0);
  color: var(--color-neutral-500);
  padding: var(--space-4) 0;
}

.footer-inner {
  width: 100%;
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: 0 var(--space-3);
  display: flex;
  flex-direction: column;
  gap: var(--space-3);
}

.footer-brand {
  max-width: 520px;
}

.footer-logo {
  font-family: var(--font-heading);
  font-size: 1rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-primary-900);
}

.footer-logo:hover,
.footer-logo:focus {
  text-decoration: none;
}

.footer-copy {
  margin-top: var(--space-1);
  font-size: 0.9rem;
}

.footer-nav-list {
  list-style: none;
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-3);
  margin: 0;
  padding: 0;
}

.footer-nav-link {
  font-size: 0.9rem;
  color: var(--color-neutral-500);
  transition: color 0.15s ease;
}

.footer-nav-link:hover,
.footer-nav-link:focus {
  color: var(--color-accent-500);
  text-decoration: none;
}

.footer-meta-text {
  margin: 0;
  font-size: 0.8rem;
}

@media (min-width: 768px) {
  .footer-inner {
    flex-direction: row;
    justify-content: space-between;
    align-items: flex-start;
  }

  .footer-nav {
    margin-left: auto;
  }

  .footer-meta {
    align-self: flex-end;
  }
}

/* Generic card pattern (for use inside #content) */
.card {
  background-color: var(--color-neutral-0);
  border-radius: var(--radius-sm);
  border: 1px solid var(--color-secondary-100);
  box-shadow: var(--shadow-card);
  padding: var(--space-4);
}

.card + .card {
  margin-top: var(--space-3);
}

/* Utility layout helpers (optional) */
.layout-two-column {
  display: grid;
  grid-template-columns: minmax(0, 2fr);
  gap: var(--space-4);
}

@media (min-width: 960px) {
  .layout-two-column {
    grid-template-columns: minmax(0, 3fr) minmax(260px, 1.4fr);
  }
}
